INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d81fd94a-547f-4b52-8585-6375a6414c6d', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$AI Site Builder$q$, $q$Generates a starting website layout, structure, and draft copy from a short description of the business, giving agencies and freelancers a faster first draft to refine.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$Drag-and-Drop Editor$q$, $q$A visual editor with responsive controls for desktop, tablet, and mobile breakpoints, letting designers adjust sections and layout without writing code.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$Client Manager Dashboard$q$, $q$A central dashboard for tracking, organizing, and maintaining many client websites at once, with team roles and permission levels for who can access what.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$White-Label Branding$q$, $q$Agencies and platform partners can present the editor and published sites under their own brand instead of Duda's, which matters for resellers and embedded use cases.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$Dynamic Pages and Content Sync$q$, $q$Shared layout or content updates can be pushed across large numbers of sites at once, useful for franchises, multi-location businesses, and templated site portfolios.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$E-Commerce Tools$q$, $q$Built-in support for online stores, product listings, and checkout, allowing client sites to sell products without a separate e-commerce platform.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$App Store and Integrations$q$, $q$A marketplace of third-party apps and integrations that extend site functionality beyond what's built into the core editor.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$Built-In SEO Tools$q$, $q$On-page SEO controls for titles, meta descriptions, and other basic optimization settings are available directly inside the site editor.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$Forms and Appointment Booking$q$, $q$Native widgets for lead-capture forms and appointment or booking scheduling, aimed at service businesses and client sites that need to take inquiries.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$API and Reseller Access$q$, $q$API access lets larger partners, such as SaaS or hosting companies, embed Duda's builder into their own product rather than sending customers to a separate tool.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$Purpose-built for agencies and teams that need to build and manage many client websites, not just a single site$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$White-label options let agencies and platforms resell the builder under their own brand$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$AI site builder speeds up the process of creating an initial draft site$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$Dynamic content sync makes maintaining large multi-site portfolios far more efficient than editing each site individually$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$Built-in client management, team roles, and billing reduce the need for separate agency tooling$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$No permanent free plan, only a free trial, so ongoing cost applies from day one$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$Can be more than a single-site user needs, both in price and in feature complexity$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$Less code-level flexibility than a fully custom-built or self-hosted solution$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$The professional, agency-oriented interface can add a learning curve for casual or first-time users$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$Migrating a large volume of existing client sites onto the platform can take meaningful time and planning$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$Does Duda have a free plan?$q$, $q$No, Duda does not offer a permanent free plan. It offers a free trial period so agencies and teams can evaluate the platform before committing to a paid subscription.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$Who is Duda designed for?$q$, $q$Duda is built primarily for web design agencies, freelancers, and SaaS or hosting companies that need to build and manage many client websites, rather than individuals creating a single personal site.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$Can I white-label Duda for my agency or platform?$q$, $q$Yes, Duda offers white-label options so agencies and partners can present the editor and published client sites under their own brand rather than Duda's.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$Does Duda support e-commerce?$q$, $q$Yes, Duda includes built-in e-commerce tools for setting up online stores, product listings, and checkout alongside its standard website-building features.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$How is Duda different from Wix or Squarespace?$q$, $q$Wix and Squarespace are built mainly for individuals creating one website, while Duda focuses on multi-site management, client hand-off, white-label branding, and API access for teams building websites at scale for other businesses.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$Agency Managing Many Client Websites$q$, $q$A web design agency uses Duda's Client Manager to build, host, and maintain dozens of client sites from a single dashboard, applying templates and shared updates instead of managing each site in isolation.$q$, $q$Digital and web design agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$SaaS or Hosting Company Offering a Website Builder$q$, $q$A SaaS platform or web hosting provider embeds Duda's white-label builder and API into its own product, letting its customers build websites without the provider building an editor from scratch.$q$, $q$SaaS companies and hosting or ISP providers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$Multi-Location Business or Franchise Sites$q$, $q$A franchise or multi-location brand uses Duda's dynamic pages and content sync to keep shared branding, offers, and layout consistent across many local pages while allowing location-specific details to vary.$q$, $q$Franchises and multi-location businesses$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$Freelance Web Designer Scaling a Client Base$q$, $q$An independent web designer uses Duda's templates and AI site builder to produce initial client drafts quickly, then relies on client roles and hand-off tools to deliver finished sites without ongoing manual maintenance.$q$, $q$Freelance and independent web designers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$Basic$q$, $q$Approximately $19-25/month (billed annually)$q$, $q$Monthly or annual, with a discount for annual billing$q$, $q$["Drag-and-drop site editor","Responsive templates","Basic on-page SEO tools","Single-site management"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$Team$q$, $q$Contact Duda for current pricing$q$, $q$Monthly or annual, with a discount for annual billing$q$, $q$["Multi-site management","Team member roles and permissions","Client Manager dashboard access","App store integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$Agency$q$, $q$Contact Duda for current pricing$q$, $q$Monthly or annual, with a discount for annual billing$q$, $q$["Expanded multi-site limits","White-label branding options","Client billing and hand-off tools","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$White Label / Custom$q$, $q$Custom / Contact sales$q$, $q$Custom$q$, $q$["Full white-label platform","API and reseller access","Dedicated account support","Tailored terms for large partners such as SaaS or hosting companies"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Duda is a website builder platform founded in 2009 and headquartered in Palo Alto, California, with additional offices supporting its product and engineering teams. Unlike consumer-facing builders that focus on one person making one site, Duda is built around helping web professionals produce and manage many websites efficiently. It combines a drag-and-drop visual editor with an AI-assisted site generator, so a base layout can be created quickly and then refined by hand.$q$, $q$The platform's core audience is web design agencies, freelance developers, marketing companies, and SaaS or hosting businesses that need to offer website creation as part of a larger service. Rather than positioning itself against Wix or Squarespace for individual consumers, Duda competes for the attention of teams that build websites for other people and need tools for collaboration, client hand-off, billing, and managing a growing roster of live sites.$q$, $q$Around the editor, Duda has built an ecosystem that includes an app store for third-party integrations, a client management dashboard, e-commerce functionality, and API access for larger partners who want to embed Duda's builder inside their own software or reseller platform. This makes it as much a business tool for running a web design practice or a white-label product line as it is a straightforward page-building tool.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$who-duda-is-for$q$, $q$Who Duda Is For$q$, 2, ARRAY[$q$Digital agencies and freelance web designers who build sites for multiple clients are Duda's most natural fit. Its client management tools, reusable templates, and team roles are designed around a workflow where one person or small team is producing and maintaining several websites at once rather than a single site for personal use.$q$, $q$SaaS companies, web hosting providers, and internet service providers that want to offer a website builder as part of their own product also use Duda, since it supports white-label branding and API access so the builder can appear as a native part of a partner's platform rather than as a separate, visibly third-party tool bolted onto an existing offering.$q$, $q$Marketing teams and organizations managing many similar sites, such as multi-location businesses, franchises, or brands running several regional or campaign microsites, benefit from Duda's dynamic pages and content-sync features, which let shared layout and content changes propagate across large numbers of sites at once instead of being edited one by one.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Someone who only wants to build one simple personal or small-business website, and who is hoping for a permanent free plan, is likely to find Duda a poor match. Duda does not offer an ongoing free tier the way some competitors do, only a free trial, so a single-site hobbyist may end up paying for capabilities they will never use.$q$, $q$Developers who want full code-level control, a headless architecture, or the flexibility of an open framework should look elsewhere. Duda is a hosted, proprietary platform, so while it supports custom code and widgets to a degree, it is not intended for teams that want to own their stack the way a custom-built site or a fully self-hosted CMS allows.$q$, $q$Very budget-conscious individuals building a first website, or anyone who does not need multi-site management, white-label branding, or client billing tools, may find simpler consumer builders like Wix or Squarespace both cheaper and easier to justify, since much of Duda's value is tied to the agency and scale features those tools don't offer at all.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The visual editor offers drag-and-drop page building, responsive design controls for desktop, tablet, and mobile breakpoints, and a library of templates spanning many industries. Duda also includes an AI site builder that generates a starting layout and copy from a short business description, along with an AI assistant that can help write, rewrite, or expand on-page text.$q$, $q$The Client Manager dashboard is central to Duda's agency positioning: it lets teams track and organize many client sites from one place, assign team member roles and permissions, and hand finished sites over to clients with limited access levels. White-label options let agencies present the builder and published sites under their own brand rather than Duda's, which matters for firms reselling web services.$q$, $q$Beyond page building, Duda includes e-commerce tools for online stores, built-in SEO controls, forms, an appointment and booking widget, and a blogging feature. An app store connects sites to third-party services, and dynamic pages with content sync allow shared data or layout changes to be pushed across many sites simultaneously, which is especially useful for franchise or multi-location deployments.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', $q$duda-experience$q$, $q$The Duda Experience$q$, 2, ARRAY[$q$Getting started typically means answering a few prompts about the business or site's purpose, after which Duda's AI generates a draft site with layout, images, and placeholder copy already in place. From there, the editor is used to adjust sections, swap out content, and fine-tune the design section by section until it matches the intended brand.$q$, $q$For agencies, the day-to-day experience centers less on any single site and more on the dashboard view of every client site the team manages: cloning templates for new projects, applying shared updates across multiple sites at once, and controlling what access a client has once a project is delivered. Billing and site-transfer options are built around this ongoing hand-off model.$q$, $q$Overall, Duda feels oriented toward professional workflows rather than casual, one-off site building. Teams that already think in terms of managing a portfolio of client sites tend to find the structure intuitive, while someone building a single personal page may find the emphasis on multi-site and client-facing features unnecessary for their needs and a bit heavier than expected.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1a2fc4b5-8703-4434-a8f7-702d91a3ded6', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
